using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===");
Console.WriteLine();

// Collect all errors and warnings
var errors = new List<(string Project, string File, int Line, int Col, string Code, string Message, string Subcategory)>();
var warnings = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();

void Visit(BaseNode node, string currentProject = "")
{
    if (node is Project p)
        currentProject = p.Name ?? currentProject;
    if (node is Target t && t.Project is Project tp)
        currentProject = tp.Name ?? currentProject;

    if (node is Error err)
    {
        errors.Add((currentProject, err.File ?? "", err.LineNumber ?? 0, err.ColumnNumber ?? 0, err.Code ?? "", err.Text ?? err.ToString(), err.Subcategory ?? ""));
    }
    if (node is Warning warn)
    {
        warnings.Add((currentProject, warn.File ?? "", warn.LineNumber ?? 0, warn.ColumnNumber ?? 0, warn.Code ?? "", warn.Text ?? warn.ToString()));
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode childNode)
                Visit(childNode, currentProject);
        }
    }
}

Visit(build);

// Print errors grouped by project
Console.WriteLine($"=== ERRORS ({errors.Count} total) ===");
Console.WriteLine();
foreach (var group in errors.GroupBy(e => e.Project))
{
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        var location = !string.IsNullOrEmpty(e.File) ? $"{e.File}({e.Line},{e.Col})" : "(no location)";
        Console.WriteLine($"  [{e.Code}] {location}");
        Console.WriteLine($"    {e.Message}");
        Console.WriteLine();
    }
}

// Print warnings (just count + notable ones)
Console.WriteLine($"=== WARNINGS ({warnings.Count} total) ===");
Console.WriteLine();
foreach (var group in warnings.GroupBy(w => w.Project))
{
    Console.WriteLine($"--- Project: {group.Key} ({group.Count()} warnings) ---");
    foreach (var w in group.Take(10))
    {
        var location = !string.IsNullOrEmpty(w.File) ? $"{w.File}({w.Line},{w.Col})" : "(no location)";
        Console.WriteLine($"  [{w.Code}] {location}");
        Console.WriteLine($"    {w.Message}");
    }
    if (group.Count() > 10)
        Console.WriteLine($"  ... and {group.Count() - 10} more warnings");
    Console.WriteLine();
}

// Show project dependency information - look for failed projects
Console.WriteLine("=== PROJECT BUILD ORDER & STATUS ===");
Console.WriteLine();

void VisitProjects(BaseNode node, int depth = 0)
{
    if (node is Project proj)
    {
        var succeeded = proj.Succeeded;
        var status = succeeded ? "OK" : "FAILED";
        var indent = new string(' ', depth * 2);
        Console.WriteLine($"{indent}[{status}] {proj.Name} ({proj.SourceFilePath})");
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode childNode)
                VisitProjects(childNode, node is Project ? depth + 1 : depth);
        }
    }
}

VisitProjects(build);

