using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Dump the full tree structure to understand project relationships
void DumpTree(BaseNode node, int depth = 0)
{
    var indent = new string(' ', depth * 2);
    var type = node.GetType().Name;

    if (node is Project p)
        Console.WriteLine($"{indent}[Project] {p.Name} -> {p.SourceFilePath}");
    else if (node is Target t)
        Console.WriteLine($"{indent}[Target] {t.Name}");
    else if (node is Task tk)
        Console.WriteLine($"{indent}[Task] {tk.Name}");
    else if (node is Error e)
        Console.WriteLine($"{indent}[ERROR] [{e.Code}] {e.Text}");
    else if (node is Message m && (m.Text?.Contains("PackageReference") == true || m.Text?.Contains("ProjectReference") == true))
        Console.WriteLine($"{indent}[Msg] {m.Text}");
    // Only go deep enough to see structure
    if (depth > 8) return;

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode childNode)
            {
                // Skip OK targets to reduce noise
                if (childNode is Target tgt && depth > 2) continue;
                DumpTree(childNode, depth + 1);
            }
        }
    }
}

// Instead, let's specifically look for project references and package references
Console.WriteLine("=== ALL PROJECTS IN BUILD ===");
var allProjects = new List<(string Name, string Path)>();
void FindProjects(BaseNode node)
{
    if (node is Project p)
    {
        allProjects.Add((p.Name ?? "?", p.SourceFilePath ?? "?"));
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
            if (child is BaseNode cn) FindProjects(cn);
    }
}
FindProjects(build);
foreach (var p in allProjects)
    Console.WriteLine($"  {p.Name} -> {p.Path}");

